package main

import (
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/mux"
	"text/template"
)

type Comment struct {
	Name  string
	Text  string
	Tags  []string
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	var comments = []Comment{
		{"John", "This is a comment with <b>bold</b> text.", []string{"author1"}},
		{"Jane", "Another comment with <i>italic</i> text.", []string{"author2"}},
	}

	tmpl, err := template.ParseFiles("comments.html")
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	err = tmpl.Execute(w, comments)
	if err != nil {
		log.Println(err)
	}
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/comments", commentsHandler).Methods("GET")

	fmt.Println("Server is running on port 8000")
	log.Fatal(http.ListenAndServe(":8000", r))
}